class ProcessOrderJob implements ShouldQueue
{
    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;

    public int $tries = 3;
    public int $backoff = 60;
    public int $timeout = 120;

    public function __construct(public readonly int $orderId) {}

    public function middleware(): array
    {
        return [new WithoutOverlapping($this->orderId)];
    }

    public function handle(OrderProcessor $processor): void
    {
        $order = Order::findOrFail($this->orderId);

        if ($order->isProcessed()) {
            return; // idempotency guard
        }

        $processor->process($order);

        NotifyCustomerJob::dispatch($this->orderId)->onQueue('notifications');
    }

    public function failed(Throwable $exception): void
    {
        Order::find($this->orderId)?->update(['status' => 'failed']);
        Log::error('Order processing failed', [
            'order_id' => $this->orderId,
            'error'    => $exception->getMessage(),
        ]);
    }

    public function retryUntil(): \DateTime
    {
        return now()->addHours(24);
    }
}

// Dispatch
ProcessOrderJob::dispatch($order->id)->onQueue('orders');

class ProcessOrderJob implements ShouldQueue
{
    public function __construct(public readonly Order $order) {} // full model — stale on retry

    public function handle(): void
    {
        try {
            OrderProcessor::process($this->order);
        } catch (\Exception $e) {
            // swallowed — retry won't work, state is unknown
        }
    }
    // no $tries, no failed(), no idempotency check
}

$batch = Bus::batch(
    User::query()->chunk(1000, fn ($chunk) =>
        $chunk->map(fn ($user) => new ExportUsersJob($user->id, $filePath))
    )
)
->then(fn ($b) => Export::find($b->options['export_id'])?->update(['status' => 'completed']))
->catch(fn ($b, $e) => Export::find($b->options['export_id'])?->update(['status' => 'failed']))
->finally(fn ($b) => Log::info("Export batch {$b->id} finished"))
->name('Export Users')
->withOption('export_id', $export->id)
->dispatch();

$export->update(['batch_id' => $batch->id]);
